-- Enrichment marathon batch: Kavita, Kayako, Kdenlive, Keap, Keeper, Keeper.sh, KeeWeb, Keila

-- ── Kavita ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Kavita is a free, open-source, self-hosted digital library server for reading and organizing manga, comics, webtoons and ebooks.$q$, short_description),
  pricing_model = COALESCE($q$Free / Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Kavita Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Kavita is a free, self-hosted digital library for manga, comics and ebooks. See features, setup requirements, pricing and top alternatives like Komga.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Kavita is a free and open-source, self-hosted reading server created by the Kareadita organization and first released publicly in 2020; the project is licensed under the GNU General Public License version 3 (GPLv3) and is maintained on GitHub, where by mid-2026 it has attracted over 11,000 stars, more than 600 forks, and dozens of active contributors, reflecting its status as one of the most widely adopted community-run alternatives to commercial digital library and comic reading platforms. Rather than being run by a venture-funded company, Kavita is built and sustained by volunteer developers who ship frequent releases (the project counts more than 75 tagged releases) and is currently labeled beta software under continuous active development. Architecturally, Kavita is a lightweight server application, written primarily in C# (.NET) on the backend with a TypeScript/Angular frontend, that a user installs on their own hardware, home server, NAS, or cloud VPS via Docker, a native binary, or platform-specific packages; once running, it scans watched folders for media files and serves a responsive web interface plus an OPDS feed to any device with a browser or OPDS-compatible reading app, meaning users retain full ownership and control of their files rather than uploading them to a third-party cloud service. The platform supports an unusually broad range of formats in a single application, including archive-based comics and manga (CBZ, CBR, CBT, CB7, ZIP, RAR, RAR5, 7ZIP, TAR.GZ, and raw image folders) as well as ebook formats (EPUB2, EPUB3, and PDF), and it ships purpose-built readers for each content type: a manga/webtoon reader with single-page, double-page, and continuous vertical webtoon modes, and a dedicated EPUB reader with customizable typography, themes, and reading settings. Kavita's feature set extends well beyond basic file serving. It offers automatic library scanning and metadata matching, rich metadata editing, custom collections and reading lists that can be curated and shared between users on the same server, bookmarking and highlighting with note-taking that can export to Obsidian, full-text and metadata-driven search across an entire library, and granular multi-user access control that lets an administrator restrict specific libraries or apply age-based content restrictions per account, with each user maintaining independent reading progress, want-to-read lists, and bookmarks. Authentication can be handled through Kavita's built-in accounts or through OpenID Connect (OIDC) for organizations wanting single sign-on. Additional conveniences include one-click send-to-Kindle/e-reader functionality, OPDS support so the library can be browsed from third-party apps, and a REST API that enables community-built companion apps and integrations. Because Kavita is fully open source and self-hosted, there is no subscription fee, no per-user pricing tier, and no vendor lock-in; the only ongoing cost is whatever hardware or hosting the user already runs (commonly a home server, Synology/QNAP NAS, Raspberry Pi, or a small cloud instance), making the effective pricing model free forever. This puts Kavita in the self-hosted media server category alongside tools like Plex, Jellyfin, and Calibre-Web for books, but its closest direct competitors are other purpose-built comic/manga library servers such as Komga (also free and open source, Java-based) and the discontinued Ubooquity, as well as commercial cloud reading services; Kavita differentiates itself through its combination of native manga/webtoon-optimized readers, deep metadata and collection tooling, multi-user permission granularity, and an actively growing plugin and companion-app ecosystem. The target audience is technically comfortable hobbyists, homelab enthusiasts, and small groups (families, friend circles, book/manga clubs) who own digital comic, manga, and ebook collections and want a private, ad-free, centrally organized way to read them from any device without relying on a commercial storefront or subscription service. Because it requires self-hosting knowledge (Docker, reverse proxy configuration, and basic server administration), Kavita is less suited to non-technical users seeking a zero-setup consumer product, but for its target self-hosting community it has become one of the most recommended tools in the space, frequently discussed on homelab and self-hosting forums as the go-to solution for a private manga and comic library.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3e4a075d-f88d-4c7c-b3da-ff99a7d73884';

