-- ── Kayako ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Kayako is a customer service and help desk platform offering ticketing, live chat, a shared inbox and pay-per-resolution AI ticket automation.$q$, short_description),
  pricing_model = COALESCE($q$Subscription with pay-per-resolution AI add-on$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing (Kay AI Agent from $1 per resolved ticket)$q$, starting_price),
  founded_year = COALESCE(2001, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Kayako Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Kayako help desk software review covering ticketing, SingleView, live chat, knowledge base and Kay AI pricing at 1 dollar per resolved ticket, plus alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Kayako is a customer service and help desk software platform founded in 2001, with origins in Jalandhar, India, before the company established its headquarters in London, United Kingdom; it also maintains additional offices in Gurgaon, India and Singapore. In February 2018 Kayako was acquired by ESW Capital, a private equity firm based in Austin, Texas that specializes in acquiring and modernizing enterprise software businesses, and Kayako has continued to operate and evolve its product under that ownership. Over more than two decades the company has built a customer base it describes as roughly 50,000 organizations across over 100 countries, with named customers including Peugeot, De Beers, NASA, and the American Motorcyclist Association. Kayako's core product is a help desk and customer support platform built around a shared team inbox and ticketing system: incoming customer messages from email, live chat, and self-service channels are consolidated into a single queue that support agents work from, with the platform's signature SingleView feature giving agents a unified view of a customer's full conversation history, past tickets, and profile data across every channel in one screen rather than forcing agents to piece together context from separate tools. Around that ticketing core, Kayako provides a self-service knowledge base and customer portal, a live chat widget for websites, SLA management and automated ticket routing rules, autoresponders, custom fields and workflow automation, reporting and analytics dashboards, and an API for building integrations with third-party systems. The most significant recent change to the product, reflected on Kayako's current pricing page, is a pivot toward AI-first, resolution-based pricing: rather than the traditional per-agent-seat subscription model used by most help desk vendors, Kayako introduced Kay, an AI support agent priced at $1 per fully resolved ticket, with no seat fees, no setup fees, and no charge for escalations or partial resolutions; the company states Kay achieves roughly a 68 percent autonomous resolution rate and positions this per-resolution cost of around $1 as dramatically cheaper than the blended cost of a human-handled ticket, which it estimates at roughly $4.60. Kay can be deployed either as an add-on layered onto a company's existing help desk platform or as part of Kayako One, Kayako's full bundled platform that combines the unified inbox, ticketing, knowledge base, live chat widget, automation rules, reporting, and the Kay AI agent together with white-glove onboarding; pricing for Kayako One itself is not publicly listed and requires contacting Kayako's sales team for a custom quote, a common practice among help desk vendors targeting mid-market and enterprise buyers. Kayako's target audience is small and mid-sized business support teams, as well as mid-market companies, that want an all-in-one help desk without assembling a stack of separate point tools, and that are increasingly interested in offloading routine ticket volume to AI to control support headcount costs. In the competitive help desk landscape, Kayako sits alongside much larger and more heavily funded platforms: Zendesk, which offers over 1,300 marketplace integrations and is generally positioned for large or complex support operations; Freshdesk, which is often cited as faster and cheaper to onboard for small and mid-sized teams with strong AI-assisted ticketing and a polished mobile experience; and Help Scout, which emphasizes simplicity and an email-centric support experience for around 12,000 customers. Reviewers and comparison sites note that Kayako's relative weaknesses versus these larger competitors include a smaller integration marketplace, less advanced native reporting and analytics, and reliance on add-ons for deeper AI functionality outside the core Kay agent. Kayako's differentiation instead rests on its unified SingleView customer context, its long operating history and enterprise customer references, and its newer resolution-based AI pricing model, which removes the seat-based cost scaling that makes competitors more expensive as a support team grows.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd6c043af-953c-4969-8e51-48311abc4eac';

