-- ── Keeper.sh ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Keeper.sh is an open-source calendar sync tool that aggregates availability across Google, Outlook, iCloud and CalDAV calendars.$q$, short_description),
  pricing_model = COALESCE($q$Freemium / Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (Pro plan $5/month)$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Keeper.sh Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Keeper.sh review: open-source calendar sync with privacy-first busy and free sharing, self-hosting and an AI-ready MCP server, pricing from free to 5 dollars.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Keeper.sh is a distinct, unrelated product from the password manager Keeper Security (keepersecurity.com); despite the similar name, Keeper.sh is an open-source calendar synchronization tool built and maintained by developer Rida F'kih and released under the AGPL-3.0 license, with its source code hosted publicly on GitHub. The product solves a specific, common scheduling problem: professionals who juggle multiple calendars across different accounts or organizations, for example a personal Google account, a work Outlook account, and a freelance or school calendar, frequently experience double-bookings because none of those calendars can see events from the others. Keeper.sh addresses this with a pull-compare-push sync engine that continuously reads events from every connected calendar, compares them, and pushes corresponding placeholder events into the other connected calendars so that busy and free time is consistently reflected everywhere, while using conflict-reconciliation logic and race-condition prevention to keep everything in sync as source events are added, moved, or deleted. By default, Keeper.sh only shares busy and free time blocks between calendars and strips out event titles, descriptions, locations, and attendee lists before syncing, prioritizing privacy; users can override this on a per-calendar basis to include titles, descriptions, custom templates, or filtered event types if they want more detail to carry over. Supported calendar connections include OAuth-based integration with Google Calendar and Microsoft Outlook, both of which use incremental sync that fetches only changed events for efficiency, CalDAV-based integration with FastMail, iCloud, and generic CalDAV servers, and read-only ingestion of standard iCal and ICS feed URLs; Keeper.sh also generates its own unique, token-authenticated iCal feed for each user so external calendar apps can subscribe to a unified view. Beyond simple two-way syncing, the tool supports flexible source-to-destination mapping, where one source calendar can push to many destinations, or many sources can consolidate into one, tags synced events with a distinguishing keeper.sh suffix or a category label in Outlook so users can tell which entries are synced placeholders versus original events, and provides real-time sync status updates over WebSocket. A notable modern addition is an optional Model Context Protocol server, which exposes read-only calendar access to AI agents and assistants, including Claude Code and Claude Desktop, through OAuth 2.1 authentication and three defined tools for listing calendars, retrieving events by date range, and counting synced events, making Keeper.sh one of a small number of calendar tools designed to be directly queryable by AI agents. Under the hood, Keeper.sh is built on a modern self-hostable stack of PostgreSQL, Redis, Bun, and a Vite and React frontend, and the project explicitly supports self-hosting through a standalone Docker Compose file, services-only containers, or fully separated microservices, in addition to a hosted cloud version. Pricing follows a simple freemium structure: a Free tier supports 2 connected accounts with 2 calendars each, syncing roughly every 30 minutes, and a basic iCal feed; a Pro tier at roughly $5 per month removes those limits, offering unlimited accounts and calendars, syncing as frequently as every minute, and priority support; and the self-hosted deployment option includes all Pro-tier features at no cost beyond the user's own infrastructure. Keeper.sh's target audience is professionals and small teams managing three or more calendars across separate organizations or ecosystems, including freelancers, consultants, people balancing a day job with side projects, and anyone who needs collision-free scheduling without manually copying events by hand. In the calendar-sync category, it competes with tools such as OneCal, CalendarBridge, and Reclaim.ai, a broader productivity suite that syncs calendars as one feature among many, though it supports only Google Calendar; Keeper.sh differentiates itself primarily through being fully open source and self-hostable, its privacy-first default of syncing only free and busy status, and its built-in MCP server for AI-agent calendar access, none of which the closed-source commercial alternatives offer.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f9315862-aea5-4bd1-8365-1d5381cc4337';

