-- ── KeeWeb ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$KeeWeb is a free, open-source, cross-platform password manager fully compatible with KeePass .kdbx database files.$q$, short_description),
  pricing_model = COALESCE($q$Free / Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$KeeWeb Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$KeeWeb review: a free open-source password manager compatible with KeePass, with cloud storage sync, self-hosting and no subscription fees.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$KeeWeb is a free and open-source password manager, released under the permissive MIT license, that was originally created in 2015 by Antelle, also known as Dimitri Witkowski, a full-stack software developer based in the Netherlands who works full time at Booking.com and built KeeWeb as an open-source side project. KeeWeb's defining characteristic is full compatibility with the KeePass ecosystem: it reads and writes the same .kdbx database file format used by KeePass and KeePassXC, meaning users already invested in KeePass-format vaults can open, edit, and save their existing password databases in KeeWeb without any conversion, and vice versa, giving them freedom to move between clients without vendor lock-in. Those .kdbx files are protected using industry-standard encryption, typically AES-256 or ChaCha20-Poly1305, and KeeWeb performs all encryption and decryption locally, never transmitting the master password or decrypted vault contents to a server it controls, since KeeWeb itself has no backend infrastructure of its own. KeeWeb is genuinely cross-platform: it ships as native-feeling desktop applications for Windows, macOS, and Linux built with Electron, and it also runs entirely as a web application in any modern browser, distributed as effectively a single self-contained HTML file, optionally paired with a service worker for offline access, which means it can be trivially self-hosted on a personal web server, a static file host, or a home lab box with zero server-side logic required. For storing and syncing the encrypted database file itself, KeeWeb integrates directly with popular cloud storage providers including Dropbox, Google Drive, OneDrive, and WebDAV, as well as supporting purely local file storage, so users can choose their own sync mechanism rather than being tied to a proprietary cloud. Functionally, KeeWeb supports opening and searching across multiple database files simultaneously, presenting results from all open files in one unified list; it includes a built-in password generator, auto-type functionality for filling credentials into other applications, support for one-time password fields stored alongside credentials, file attachments within entries, and customizable interface themes including dark mode. As development has continued, the project has been sustained on a community basis rather than by a company or full-time maintainer; its original creator stepped back from active day-to-day development in the early 2020s and the project has continued as what its own repository describes as a hobby project without a dedicated organization, funded informally through GitHub Sponsors and Open Collective donations, though the codebase has continued to receive updates and releases into 2026. Because KeeWeb is entirely free, open source, and self-hostable, it has no pricing tiers, subscription plans, or premium features of any kind, the entire application is available at no cost, with its only real cost being that a user must supply their own file storage or cloud account for syncing. KeeWeb's target audience is privacy-conscious individuals and technically inclined users who are already using or want to use the open KeePass file format, particularly those who want a more modern interface than the traditional KeePass or KeePassXC desktop clients, or who want browser-based or self-hosted access to their vault without paying for a commercial password manager's cloud subscription. In the password manager category, KeeWeb's closest peers are other KeePass-format-compatible clients such as KeePassXC and the original KeePass, with which it is directly interoperable rather than competitive, and it is more broadly an alternative to commercial cloud password managers such as Keeper Security, 1Password, Bitwarden, and Dashlane; KeeWeb differentiates itself from those commercial products by having no company, no subscription, no seat pricing, and no proprietary vault format, instead giving users full ownership of a portable, standards-based encrypted file that can be opened by multiple independent applications, at the cost of the polished onboarding, customer support, and integrated breach-monitoring features that funded commercial products provide.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'adba4fa4-52c9-43d9-aa36-5bf99f7c06f0';

