-- ── Keila ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Keila is an open-source, privacy-focused email newsletter platform that can be self-hosted or used as an EU-hosted managed cloud service.$q$, short_description),
  pricing_model = COALESCE($q$Open Source (self-hosted); Subscription (Keila Cloud)$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); EUR 8/month (Keila Cloud XS plan)$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Keila Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Keila review: open-source Mailchimp alternative with self-hosting, EU-hosted cloud pricing from 8 euros per month, and GDPR-friendly analytics.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Keila is an open-source email newsletter and marketing platform built with the Elixir programming language and the Phoenix web framework, developed by the GitHub organization and maintainer pentacent and operated commercially as Pentacent, Philipp Schmieder Medien, a Germany-based operation; the software itself is released under the GNU Affero General Public License version 3, a strong copyleft license, and its source code is publicly hosted on GitHub where the project has accumulated over 2,000 stars. Keila positions itself explicitly as an open-source alternative to commercial newsletter and email marketing tools such as Mailchimp and Sendinblue (Brevo), built around a stated philosophy of privacy-first, GDPR-friendly email marketing with no proprietary premium features gated behind the open-source version, the company states plainly that Keila is 100 percent open source with no proprietary components, meaning the self-hosted version is functionally identical to the paid, managed version. The product covers the core workflow of running an email newsletter: composing campaigns using a visual block-based editor, plain Markdown, or full custom HTML and MJML templates for teams wanting complete design control; building and embedding customizable sign-up forms with configurable fields, checkboxes, and dropdowns to grow a subscriber list; segmenting contacts using either a visual segment editor or a more powerful query-style segment language to target campaigns at specific subsets of subscribers; and reviewing privacy-conscious campaign analytics that can be disabled entirely with one click for organizations that do not want to track opens and clicks at all. Keila includes bot protection for signup forms via hCaptcha or Friendly Captcha, double opt-in confirmation flows, Liquid templating syntax for personalizing email content with dynamic contact or JSON data, and a REST API for programmatically managing contacts and campaigns, with a Zapier integration available in beta. For actually sending mail, Keila does not operate as a closed platform locked to its own infrastructure, it supports direct SMTP configuration as well as native integrations with major transactional email providers including Amazon SES, SendGrid, Mailgun, and Postmark, so self-hosters can route mail through whichever provider they already trust. Keila can be run in two ways: fully self-hosted via an official Docker image on a user's own server, which is entirely free of charge beyond the user's own infrastructure and mail-sending provider costs; or as Keila Cloud, a managed hosted version of the software run entirely on servers located in Germany and France, marketed specifically on the basis of strict European Union data-privacy standards. Keila Cloud pricing is structured in six volume-based tiers rather than by contact count, since contacts and projects are unlimited on every plan: an XS plan at EUR 8 per month for up to 2,000 emails sent, an S plan at EUR 16 per month for up to 5,000 emails, an M plan at EUR 32 per month for up to 15,000 emails, an L plan at EUR 64 per month for up to 50,000 emails, an XL plan at EUR 128 per month for up to 100,000 emails, and an XXL plan at EUR 256 per month for up to 250,000 emails; notably, Keila deliberately offers no permanent free tier, with the company explaining its reasoning directly on its pricing page, that a free email tool typically means the user's data is the real product, so instead Keila offers discretionary discounts for open-source projects and registered nonprofits evaluated case by case. Keila's target audience includes privacy-conscious small businesses, nonprofits, community organizations, political and advocacy groups, open-source projects, and developers who want either a lightweight self-hosted newsletter tool with no vendor lock-in or a paid European-hosted alternative to Mailchimp-style platforms for GDPR-compliance reasons. Within the open-source newsletter category, Keila is most often compared with Listmonk, a Go-based, single-binary newsletter manager that is generally regarded as lighter-weight and able to run on cheaper infrastructure at large subscriber volumes, Mailcoach, a Laravel-based tool from Spatie that supports bring-your-own-provider sending and offers more built-in automation workflows than Keila, and Mautic, a much larger, more full-featured open-source marketing-automation platform used by over 200,000 organizations; reviewers generally describe Keila as the newest and most minimally designed of these tools, with a cleaner and more modern interface but a smaller community and fewer production-hardened integrations than its more established competitors.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c94c98e6-ef4f-4e3b-95b2-929dc548f9d9';

