INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$Multi-format library$q$, $q$Supports CBZ, CBR, CB7, ZIP, RAR, 7ZIP, PDF and EPUB in a single unified server.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$Purpose-built readers$q$, $q$Dedicated manga, webtoon and EPUB readers with single-page, double-page and continuous scroll modes.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$Multi-user access control$q$, $q$Per-library and age-based restrictions with independent reading progress for each account.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$Metadata and collections$q$, $q$Automatic library scanning, metadata editing, and curated reading lists shareable between users.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$OPDS and REST API$q$, $q$Exposes the library to third-party e-reader apps and enables custom integrations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$Send to device$q$, $q$One-click delivery of content to Kindle and other e-readers for offline reading.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$OIDC authentication$q$, $q$Supports single sign-on for organizations alongside built-in login accounts.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$Highlighting and notes$q$, $q$In-book highlighting and note-taking with export support to Obsidian.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$Completely free and open source with no premium tier$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$Broad format support in a single application, covering comics, manga, webtoons and ebooks$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$Strong multi-user permission and parental-control system$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$Active development with frequent releases and a large community$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$Full data ownership since everything runs on the user's own server$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$Requires self-hosting knowledge, including Docker and reverse proxy setup$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$Still labeled beta software with occasional bugs$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$No official vendor support or SLA$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$No built-in content acquisition, users must supply their own files$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$Mobile experience relies on the web app or third-party clients rather than a first-party app$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$Is Kavita free?$q$, $q$Yes. Kavita is completely free and open source under the GPLv3 license, with no premium tiers or paid add-ons.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$What file formats does Kavita support?$q$, $q$Kavita supports CBZ, CBR, CBT, CB7, ZIP, RAR, RAR5, 7ZIP, TAR.GZ, raw image folders, EPUB2, EPUB3 and PDF.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$Does Kavita require self-hosting?$q$, $q$Yes, Kavita must be installed on your own server, NAS, or VPS via Docker, a native binary, or a platform package.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$Can multiple people use one Kavita server?$q$, $q$Yes, Kavita supports multiple user accounts with granular per-library and age-based permission controls.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$What is the difference between Kavita and Komga?$q$, $q$Both are free self-hosted comic servers; Kavita additionally offers native ebook readers for EPUB and PDF plus OIDC login support.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$Does Kavita have mobile apps?$q$, $q$Kavita is accessed through a responsive web app and OPDS-compatible reading apps; there is no single official first-party mobile app.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$Personal manga and comic library$q$, $q$Collectors organize and read their manga, comic and webtoon collections from a private, self-hosted server.$q$, $q$Manga and comic collectors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$Family ebook and comic sharing$q$, $q$Households share a common library while keeping separate reading progress and age-based access per family member.$q$, $q$Families and friend groups$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$Homelab media stack addition$q$, $q$Self-hosting enthusiasts add Kavita alongside tools like Plex or Jellyfin to complete a private media server setup.$q$, $q$Homelab and self-hosting enthusiasts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$Self-Hosted$q$, $q$Free$q$, $q$Free forever$q$, NULL, $q$["Unlimited libraries, users and devices","All readers and formats included","OPDS feed and REST API access","Community support via Discord and GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kavita is a free, open-source reading server built by the Kareadita community and first released in 2020 under the GPLv3 license. It lets anyone turn their own hardware, whether a home server, NAS, or cloud VPS, into a private digital library for manga, comics, webtoons and ebooks, accessible from any browser or OPDS-compatible app.$q$, $q$Unlike commercial cloud reading subscriptions, Kavita keeps every file under the user's own control. It scans watched folders, pulls in metadata, and serves the content through dedicated readers, with no recurring fees, ads, or vendor lock-in at any point.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Kavita supports an unusually wide range of formats in one application, from archive-based comics (CBZ, CBR, CB7, ZIP, RAR, 7ZIP) to ebooks (EPUB2, EPUB3, PDF), each served through a purpose-built reader with single-page, double-page, and continuous webtoon display modes.$q$, $q$Beyond reading, Kavita offers granular multi-user permissions with per-library and age-based restrictions, custom reading lists and collections, highlighting and note export to Obsidian, OIDC single sign-on, and a REST API and OPDS feed for third-party app compatibility.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Kavita has no pricing tiers, subscriptions, or paywalled features of any kind. The entire application is free and open source, funded purely through volunteer development rather than commercial revenue.$q$, $q$The only real cost is infrastructure: users need their own server or hosting environment capable of running Docker or a native binary, which for most homelab users means an existing NAS, Raspberry Pi, or small VPS they already own.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3e4a075d-f88d-4c7c-b3da-ff99a7d73884', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Shared team inbox and ticketing$q$, $q$Consolidates email, chat and self-service requests into a single queue for support agents.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$SingleView$q$, $q$Unified view of a customer's full conversation history and profile data across every channel.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Live chat widget$q$, $q$Embeddable website chat that feeds directly into the shared ticketing queue.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Self-service knowledge base$q$, $q$Customer portal and help center to deflect routine tickets before they reach agents.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$SLA management and routing$q$, $q$Automated ticket routing, autoresponders and service-level agreement enforcement.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Kay AI agent$q$, $q$Pay-per-resolution AI ticket automation billed only when a ticket is fully resolved.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Reporting and analytics$q$, $q$Dashboards for tracking ticket volume, resolution rates and team performance.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$API and integrations$q$, $q$REST API for connecting Kayako to third-party business systems.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Unified SingleView gives agents full customer context in one screen$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Resolution-based Kay AI pricing avoids seat-cost scaling as ticket volume grows$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Long operating history since 2001 with enterprise references like NASA and Peugeot$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Combines ticketing, chat and knowledge base in one platform$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$No setup or seat fees for the Kay AI add-on$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Smaller integration marketplace than Zendesk$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Advanced reporting and analytics are more limited than larger competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Kayako One platform pricing is not publicly listed and requires a sales call$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Deeper AI functionality outside Kay may require add-ons$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Smaller market share means fewer independent implementation partners$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$What is Kayako?$q$, $q$Kayako is a customer service and help desk platform offering ticketing, live chat, a knowledge base and AI-driven ticket resolution.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$How much does Kayako cost?$q$, $q$The Kay AI agent costs $1 per resolved ticket with no seat fees; the full Kayako One platform requires a custom quote from sales.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Who owns Kayako?$q$, $q$Kayako has been owned by ESW Capital, a private equity firm based in Austin, Texas, since February 2018.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$What is SingleView?$q$, $q$SingleView is Kayako's feature that unifies a customer's conversation history and profile data across channels in one agent screen.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Does Kayako offer a free trial?$q$, $q$Kayako's pricing page directs prospective customers toward a demo or sales quote rather than a widely advertised self-serve free trial.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Who are Kayako's main competitors?$q$, $q$Kayako's primary competitors include Zendesk, Freshdesk and Help Scout.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$SMB customer support consolidation$q$, $q$Small business teams replace multiple disconnected support tools with one shared inbox and knowledge base.$q$, $q$Small business support teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Multichannel enterprise support$q$, $q$Larger support organizations use SingleView to manage complex, multichannel customer relationships.$q$, $q$Mid-market and enterprise support teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$AI-augmented ticket deflection$q$, $q$Support operations teams add the Kay AI agent to cut per-ticket resolution costs without adding headcount.$q$, $q$Support operations leaders$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Kay AI Agent$q$, $q$$1 per resolved ticket$q$, $q$Pay-per-resolution$q$, NULL, $q$["No seat fees","No setup fees","No charge for escalations or partial resolutions","Reported 68 percent AI resolution rate"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$Kayako One$q$, $q$Custom pricing$q$, $q$Custom quote$q$, NULL, $q$["Unified inbox and ticketing","Knowledge base and self-service portal","Live chat widget","Automation rules and reporting","Kay AI agent included","White-glove onboarding"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kayako is a help desk and customer service platform founded in 2001 and now headquartered in London, with additional offices in India and Singapore. Since being acquired by ESW Capital in 2018, the company has continued serving an estimated 50,000 customers across more than 100 countries, including names like NASA and Peugeot.$q$, $q$The platform centers on a shared inbox and ticketing system enhanced by SingleView, a feature that consolidates a customer's full history across email, chat and self-service into one agent screen, reducing the need to jump between tools to understand context.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include ticket management, live chat, a self-service knowledge base, SLA management, automated routing, custom workflows and reporting dashboards, all accessible through an API for third-party integrations.$q$, $q$The newest addition is Kay, an AI support agent priced per resolved ticket rather than per seat, which the company reports resolves roughly 68 percent of tickets autonomously and can be added to an existing help desk or bundled into the full Kayako One platform.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Kayako has moved away from traditional seat-based pricing toward a resolution-based model for its AI agent: Kay costs $1 per fully resolved ticket with no setup or seat fees, and no charge for escalated or partially resolved conversations.$q$, $q$The full Kayako One platform, bundling ticketing, chat, knowledge base and Kay together with onboarding support, is not listed at a fixed public price and requires contacting Kayako's sales team for a custom quote based on team size and needs.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d6c043af-953c-4969-8e51-48311abc4eac', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$Unlimited multi-track timeline$q$, $q$Supports an unlimited number of video and audio tracks for complex edits.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$Built-in title editor$q$, $q$Create and animate text and title clips directly inside the application.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$Proxy clip editing$q$, $q$Edit smoothly with high-resolution footage by working from lower-resolution proxies.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$Keyframeable effects and transitions$q$, $q$Apply and animate effects and transitions with fine-grained keyframe control.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$Color scopes$q$, $q$Waveform, histogram and vectorscope tools for color correction and grading.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$Speech-to-text transcription$q$, $q$Automatically transcribe spoken audio in a project's clips.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$Motion tracking and scene detection$q$, $q$Track motion within footage and automatically detect scene cuts.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$Broad format support$q$, $q$Handles nearly any video or audio format via the underlying FFmpeg and MLT stack.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$Completely free with no watermarks or feature paywalls$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$Professional-grade feature set rivaling some paid editors$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$Cross-platform support for Windows, macOS and Linux$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$Active, KDE-backed volunteer development community$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$Strong integration with the Linux desktop ecosystem$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$Can be less stable than mature commercial editors on complex projects$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$Steeper learning curve than simplified editors like OpenShot$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$Color grading and audio post-production tools are less advanced than DaVinci Resolve's Fairlight and color pages$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$Rendering performance depends heavily on system hardware and the underlying FFmpeg build$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$No official paid support channel$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$Is Kdenlive really free?$q$, $q$Yes, Kdenlive is entirely free and open source under the GPL, with no paid tiers, watermarks, or subscriptions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$What platforms does Kdenlive support?$q$, $q$Kdenlive runs on Windows, macOS and Linux.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$What engine powers Kdenlive?$q$, $q$Kdenlive's interface is built with Qt and KDE Frameworks, while video and audio processing runs through the MLT Framework and FFmpeg.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$Who develops Kdenlive?$q$, $q$Kdenlive is developed by volunteer contributors under KDE e.V., the nonprofit organization behind the KDE community.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$How does Kdenlive compare to DaVinci Resolve?$q$, $q$Kdenlive is fully free and open source and lighter weight, while DaVinci Resolve offers stronger color grading and audio tools with an optional paid Studio tier.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$Can I use Kdenlive for commercial projects?$q$, $q$Yes, the GPL license permits using Kdenlive to produce and sell commercial video work.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$Independent content creation$q$, $q$YouTubers and independent creators edit videos without paying for a subscription-based editor.$q$, $q$Independent creators and YouTubers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$Linux desktop video editing$q$, $q$Linux users get a fully native, actively maintained non-linear editor integrated with their desktop.$q$, $q$Linux users and homelab enthusiasts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$Educational and student film editing$q$, $q$Students and educators use Kdenlive to teach and practice video editing without licensing costs.$q$, $q$Students and educators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$Open Source$q$, $q$Free$q$, $q$Free forever$q$, NULL, $q$["Unlimited tracks and projects","All effects and export formats included","Community and forum support","Optional donations to KDE e.V."]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kdenlive began in 2002 as a project started by Jason Wood, stalled, and was revived in 2005 by Jean-Baptiste Mardelle, who led its migration to the MLT framework and KDE 4. It became an official KDE project in 2015 and received a major refactor in the 2019.04 KDE Applications release.$q$, $q$Today it is maintained entirely by volunteer contributors under KDE e.V., the nonprofit that supports the KDE community, with no company or commercial tier behind it.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The interface is built in C++ with Qt, while all video and audio processing runs through the MLT Framework and FFmpeg underneath, giving Kdenlive support for virtually every common video and audio format alongside effects libraries like Frei0r and Movit.$q$, $q$Editors get an unlimited multi-track timeline, a title editor, proxy-clip workflows for smooth high-resolution editing, keyframeable effects, color scopes for grading, speech-to-text transcription, motion tracking and scene detection.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Kdenlive is entirely free, with no subscription, watermark, or feature-gated tier of any kind, distributed under the GPL for Windows, macOS and Linux.$q$, $q$Development is funded through voluntary donations to KDE e.V. rather than product revenue, which keeps the editor free while supporting ongoing contributor work and infrastructure.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0b8a01cb-eaf5-4307-9fc0-f73aa6bf0bec', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
