INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$What was Keap previously called?$q$, $q$Keap was previously known as Infusionsoft before rebranding in 2019, and before that as eNovaSys.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Who founded Keap?$q$, $q$Keap was founded in 2001 by Clate Mask and Scott Martineau in Chandler, Arizona.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Who owns Keap now?$q$, $q$Keap has been owned by Thryv, a small-business software company, since 2024.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$How much does Keap cost?$q$, $q$Keap's plans run roughly from $249 per month for Pro to $349 per month for Ultimate, billed annually, plus additional user and onboarding fees.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Does Keap charge for onboarding?$q$, $q$Yes, most new Pro and Max customers must purchase a one-time Kickstart onboarding package priced at roughly $499 to $999.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Who are Keap's main competitors?$q$, $q$Keap's main competitors include HubSpot, ActiveCampaign and entry-level Salesforce products.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Solo entrepreneur automation$q$, $q$Coaches and consultants automate follow-up and nurture sequences without needing a marketing team.$q$, $q$Coaches and consultants$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Service business lead-to-invoice workflow$q$, $q$Contractors and agencies manage leads through to invoicing and payment in one connected system.$q$, $q$Contractors and agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Small business marketing automation$q$, $q$Non-technical small business owners run sophisticated automated campaigns without hiring developers.$q$, $q$Non-technical small business owners$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Pro$q$, $q$Approximately $249/month$q$, $q$Billed annually$q$, NULL, $q$["2 user licenses included","Approximately 1,500 contacts","CRM, email and SMS automation, landing pages","Kickstart onboarding required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Max$q$, $q$Approximately $299/month$q$, $q$Billed annually$q$, NULL, $q$["2 user licenses included","Approximately 2,500 contacts","Advanced automation and lead scoring","Kickstart onboarding required"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$Ultimate$q$, $q$Approximately $349/month$q$, $q$Billed annually$q$, NULL, $q$["Highest contact and automation limits","Priority support","Full platform access"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Keap was founded in 2001 in Chandler, Arizona by Clate Mask and Scott Martineau as eNovaSys, rebranded to Infusionsoft in 2004, and rebranded again to Keap in 2019 to simplify its product for non-technical small business owners. Thryv acquired Keap in 2024.$q$, $q$The platform combines a contact-record CRM, marketing automation, sales pipeline management, and invoicing into one system aimed at small and service-based businesses.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Keap's core is a CRM paired with a visual automation builder for multi-step email and SMS sequences triggered by customer behavior, alongside a sales pipeline for tracking deals.$q$, $q$Additional tools include landing page and form builders, appointment scheduling, quote and invoice generation with payment collection, and a mobile app for managing contacts and communication on the go.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Keap's current plans are Pro at roughly $249 per month, Max at roughly $299 per month, and Ultimate at roughly $349 per month, billed annually, each including two user licenses with contact limits that scale by tier.$q$, $q$Additional users cost roughly $39 to $59 per month each, and new Pro and Max customers are generally required to purchase a one-time Kickstart onboarding package priced at roughly $499 to $999, with optional SMS and voice minute bundles available on top.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e36dac6a-4141-4189-8ee8-eb6f2ed8f21f', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
