INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Is Keeper the same as Keeper.sh?$q$, $q$No. Keeper Security (keepersecurity.com) is a password manager, while Keeper.sh is an unrelated open-source calendar sync tool.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$How much does Keeper Personal cost?$q$, $q$The Personal plan costs roughly $4 per month when billed annually.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Is Keeper open source?$q$, $q$No, Keeper is closed source, unlike its competitor Bitwarden.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$What compliance certifications does Keeper hold?$q$, $q$Keeper holds FedRAMP High authorization, FIPS 140-3 validation, and ITAR compliance.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Who founded Keeper Security?$q$, $q$Keeper Security was founded in 2009 by Darren Guccione and Craig Lurey.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$What is KeeperPAM?$q$, $q$KeeperPAM is Keeper's bundled privileged access management suite that adds secrets management and remote access controls to the core password manager.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Family password protection$q$, $q$Individuals and families store and share passwords securely across up to five vaults.$q$, $q$Individuals and families$q$, 0);
