INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Business$q$, $q$Approximately $3.75/user/month$q$, $q$Billed annually$q$, NULL, $q$["Advanced sharing and reporting","SSO options"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Enterprise$q$, $q$Approximately $6-$7.50/user/month$q$, $q$Billed annually$q$, NULL, $q$["Advanced compliance and reporting","SCIM and directory integrations"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$Enterprise Plus$q$, $q$Approximately $12-$15+/user/month$q$, $q$Billed annually$q$, NULL, $q$["KeeperPAM privileged access management","Secrets management (KSM)","Connection Manager remote access"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Keeper Security was founded in 2009 by Darren Guccione and Craig Lurey and is headquartered in Chicago, with offices in California, Ireland and the Philippines. The company has raised roughly $60 million, including a Series D round from Insight Partners in 2023.$q$, $q$Keeper uses a zero-knowledge architecture where encryption and decryption happen locally on the user's device, so Keeper's own servers never see unencrypted vault data or master passwords.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Beyond core password storage, Keeper includes BreachWatch dark web monitoring, KeeperChat encrypted messaging, Keeper Secrets Manager for DevOps credential storage, Keeper Connection Manager for agentless remote access, and KeeperPAM for privileged access management.$q$, $q$The company holds deep compliance certifications including FedRAMP High, FIPS 140-3 and ITAR, making it a common choice for government, defense and regulated enterprise customers, and it has begun rolling out quantum-resistant cryptography.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Consumer pricing starts with a Personal plan at roughly $4 per month billed annually, and a Family plan covering up to five vaults with 10GB of shared storage at a modest premium.$q$, $q$Business pricing runs from roughly $2 per user per month for Business Starter up to $12 to $15-plus per user per month for Enterprise Plus, which adds KeeperPAM and secrets management on top of core password management.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cb3933a8-b7e0-4fcb-a19a-28725cbedc5d', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
