INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$Pull-compare-push sync engine$q$, $q$Continuously reads, compares and pushes events across every connected calendar.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$Privacy-first sharing$q$, $q$Shares only busy and free time by default, stripping titles and details unless opted in.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$OAuth calendar support$q$, $q$Connects to Google Calendar and Microsoft Outlook with incremental sync.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$CalDAV support$q$, $q$Connects to iCloud, FastMail and generic CalDAV servers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$iCal and ICS feeds$q$, $q$Reads external ICS feeds and generates a unique token-authenticated feed per user.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$Flexible calendar mapping$q$, $q$Supports one-to-many and many-to-one sync configurations.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$Real-time sync status$q$, $q$WebSocket-based status updates as calendars sync.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$MCP server for AI agents$q$, $q$Optional OAuth 2.1 protected server giving AI assistants read-only calendar access.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$Fully open source under AGPL-3.0 and self-hostable$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$Privacy-first default that strips event details before syncing$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$Built-in MCP server enables AI agents to query calendars directly$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$Affordable Pro tier with fast 1-minute sync intervals$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$Supports a wide range of calendar providers and protocols$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$Free tier is limited to 2 accounts and 2 calendars each$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$Built and maintained by a single developer, raising long-term support questions$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$Newer product with a smaller track record than established competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$Self-hosting requires technical setup involving PostgreSQL, Redis and Docker$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$Free tier sync interval of 30 minutes is slow compared to the paid tier$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$Is Keeper.sh the same as Keeper Security?$q$, $q$No, Keeper.sh is an entirely different, unrelated product from the Keeper Security password manager.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$Is Keeper.sh free?$q$, $q$Yes, a free tier exists with 2 accounts and 2 calendars each; the Pro tier costs roughly $5 per month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$Can I self-host Keeper.sh?$q$, $q$Yes, Keeper.sh can be self-hosted via Docker, including all Pro-tier features.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$What calendars does Keeper.sh support?$q$, $q$Keeper.sh supports Google Calendar, Outlook, iCloud, FastMail, generic CalDAV servers and ICS feeds.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$Does Keeper.sh share event details?$q$, $q$No, by default it only shares busy and free time; sharing titles or descriptions is opt-in per calendar.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$Does Keeper.sh work with AI assistants?$q$, $q$Yes, an optional MCP server gives AI agents like Claude read-only access to calendar data.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$Freelancer calendar management$q$, $q$Freelancers and consultants prevent double-bookings across client and personal calendars.$q$, $q$Freelancers and consultants$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$Cross-organization scheduling$q$, $q$Professionals with separate work and personal calendars keep availability consistent everywhere.$q$, $q$Professionals with multiple work calendars$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$AI-agent scheduling access$q$, $q$Developers integrate AI assistants with calendar data through the built-in MCP server.$q$, $q$Developers integrating AI assistants$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$Free$q$, $q$Free$q$, $q$Free$q$, NULL, $q$["2 connected accounts","2 calendars per account","30-minute sync interval","Basic iCal feed"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$Pro$q$, $q$$5/month$q$, $q$Monthly$q$, NULL, $q$["Unlimited accounts and calendars","1-minute sync interval","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$Self-Hosted$q$, $q$Free (self-hosted)$q$, $q$Free forever$q$, NULL, $q$["All Pro-tier features included","Full control of data via Docker deployment"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Keeper.sh is an open-source calendar synchronization tool, unrelated to the password manager Keeper Security, built by developer Rida F'kih and released under the AGPL-3.0 license. It solves double-booking problems for people juggling multiple calendars across accounts and organizations.$q$, $q$The tool uses a pull-compare-push sync engine to keep busy and free time consistent across every connected calendar, with conflict reconciliation and race-condition prevention built in.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Keeper.sh connects to Google Calendar and Outlook via OAuth, to FastMail and iCloud via CalDAV, and to any generic iCal or ICS feed in read-only mode, with flexible one-to-many or many-to-one mapping between calendars.$q$, $q$By default only busy and free time is shared, with event titles, descriptions and attendees stripped out unless a user opts in per calendar. An optional MCP server also gives AI agents read-only access to calendar data.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$A Free tier covers 2 accounts with 2 calendars each and syncs every 30 minutes, while the Pro tier at roughly $5 per month removes those limits and syncs every minute with priority support.$q$, $q$Keeper.sh can also be self-hosted via Docker, which includes all Pro-tier features at no cost beyond the user's own infrastructure.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f9315862-aea5-4bd1-8365-1d5381cc4337', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$Full KeePass compatibility$q$, $q$Reads and writes standard .kdbx database files used by KeePass and KeePassXC.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$Local AES-256/ChaCha20 encryption$q$, $q$All encryption and decryption happens locally on the user's device.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$Cross-platform desktop apps$q$, $q$Native-feeling apps for Windows, macOS and Linux built with Electron.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$Browser-based web app$q$, $q$Runs entirely in the browser as a self-contained HTML file with no installation required.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$Cloud storage integration$q$, $q$Syncs database files via Dropbox, Google Drive, OneDrive or WebDAV.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$Multi-file search$q$, $q$Opens and searches across multiple database files at once.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$Password generator and auto-type$q$, $q$Built-in password generation and auto-fill into other applications.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$Customizable themes$q$, $q$Includes dark mode and other interface themes.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$Completely free and open source under the MIT license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$Full interoperability with KeePass and KeePassXC via the .kdbx format$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$No vendor lock-in, works with any cloud storage or local files$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$Can be self-hosted as a single static HTML file$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$Available as both a desktop app and a browser-based web app$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$No dedicated official mobile app$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$Maintained as a community hobby project without a full-time maintainer$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$No built-in breach monitoring or dark web alerts$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$Support is community-based with no formal service level agreement$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$Feature development has slowed compared to commercial competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$Is KeeWeb free?$q$, $q$Yes, KeeWeb is entirely free and open source under the MIT license.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$Is KeeWeb compatible with KeePass?$q$, $q$Yes, KeeWeb fully supports the .kdbx database format used by KeePass and KeePassXC.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$Who created KeeWeb?$q$, $q$KeeWeb was created in 2015 by Antelle, also known as Dimitri Witkowski, a developer based in the Netherlands.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$Can KeeWeb sync with cloud storage?$q$, $q$Yes, KeeWeb integrates with Dropbox, Google Drive, OneDrive and WebDAV.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$Is KeeWeb self-hostable?$q$, $q$Yes, KeeWeb can be self-hosted as a single self-contained HTML file on any web server.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$Does KeeWeb have a mobile app?$q$, $q$There is no official KeeWeb mobile app; users typically use another KeePass-compatible mobile app with the same .kdbx file.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$KeePass users wanting a modern interface$q$, $q$Existing KeePass and KeePassXC users switch to KeeWeb for a more modern, browser-friendly interface while keeping the same database.$q$, $q$Existing KeePass and KeePassXC users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$Self-hosted password management$q$, $q$Privacy-conscious self-hosters run KeeWeb on their own server for full control over their vault.$q$, $q$Privacy-conscious self-hosters$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$Browser-based access without installation$q$, $q$Users needing quick cross-device vault access use the web version without installing anything.$q$, $q$Users needing quick cross-device access$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$Open Source$q$, $q$Free$q$, $q$Free forever$q$, NULL, $q$["Unlimited entries and databases","Desktop apps for Windows, macOS and Linux","Web app version","Cloud storage integrations included"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$KeeWeb was created in 2015 by Antelle, a Netherlands-based developer, as an open-source password manager fully compatible with the KeePass .kdbx file format. It is released under the MIT license and has continued as a community-maintained hobby project.$q$, $q$It ships as desktop apps for Windows, macOS and Linux, and as a browser-based web app distributed as a single self-contained HTML file, making it easy to self-host anywhere.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$KeeWeb reads and writes standard .kdbx database files encrypted with AES-256 or ChaCha20-Poly1305, with all encryption and decryption happening locally on the user's device.$q$, $q$It integrates with Dropbox, Google Drive, OneDrive and WebDAV for syncing, supports opening and searching across multiple database files at once, and includes a password generator, auto-type, and customizable themes.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$KeeWeb is entirely free and open source with no subscription tiers, premium features, or paid add-ons of any kind.$q$, $q$The only ongoing cost is whatever cloud storage or hosting a user chooses to sync or host their .kdbx database file, since KeeWeb itself has no backend service to pay for.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('adba4fa4-52c9-43d9-aa36-5bf99f7c06f0', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
