INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$Visual and Markdown email editor$q$, $q$Compose campaigns with a block-based visual editor, Markdown, or custom MJML templates.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$Sign-up form builder$q$, $q$Create and embed customizable subscription forms with configurable fields.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$Contact segmentation$q$, $q$Segment contacts using a visual editor or a powerful query-style segment language.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$Privacy-respecting analytics$q$, $q$Campaign analytics that can be fully disabled with one click for privacy-first organizations.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$Double opt-in and bot protection$q$, $q$hCaptcha or Friendly Captcha integration plus double opt-in confirmation flows.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$Liquid personalization$q$, $q$Dynamic email content personalization using the Liquid templating language.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$REST API$q$, $q$Programmatic management of contacts and campaigns, with a beta Zapier integration.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$Bring-your-own email provider$q$, $q$Send via SMTP, Amazon SES, SendGrid, Mailgun or Postmark.$q$, 7);
