INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$Self-hosted version is free and functionally identical to paid Keila Cloud$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$EU-hosted managed option in Germany and France supports strict GDPR compliance$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$Privacy-first analytics that can be fully disabled$q$, 3);
