INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$No permanent free tier for the managed Keila Cloud service$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$Smaller community and fewer integrations than Mailchimp or Mautic$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$Fewer built-in automation workflows than competitors like Mailcoach$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$Newer and less production-hardened than more established open-source tools like Listmonk$q$, 3);
