INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$Is Keila free?$q$, $q$The self-hosted version is completely free; the managed Keila Cloud service starts at EUR 8 per month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$Is Keila open source?$q$, $q$Yes, Keila is 100 percent open source under the AGPLv3 license with no gated premium features.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$Where is Keila Cloud hosted?$q$, $q$Keila Cloud runs entirely on servers located in Germany and France.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$What email providers does Keila support?$q$, $q$Keila supports direct SMTP as well as Amazon SES, SendGrid, Mailgun and Postmark.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$Does Keila offer automation workflows?$q$, $q$Keila offers basic automation but fewer built-in workflows than competitors like Mailcoach or Mautic.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$How does Keila compare to Mailchimp?$q$, $q$Keila is an open-source, self-hostable alternative to Mailchimp with unlimited contacts on every plan and an EU-hosted option for GDPR compliance.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$GDPR-conscious European newsletters$q$, $q$EU businesses and nonprofits send newsletters through EU-hosted infrastructure to meet strict privacy requirements.$q$, $q$EU businesses and nonprofits$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$Self-hosted developer newsletter$q$, $q$Developers and open-source projects self-host Keila for full control with no per-contact fees.$q$, $q$Developers and open-source projects$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$Nonprofit and advocacy campaigns$q$, $q$Nonprofits and community groups run email campaigns while respecting subscriber privacy.$q$, $q$Nonprofits and advocacy groups$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$Self-Hosted$q$, $q$Free$q$, $q$Free forever (Docker)$q$, NULL, $q$["Unlimited contacts and projects","All features included, no premium gate","Bring your own email provider"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$Keila Cloud XS$q$, $q$EUR 8/month$q$, $q$Monthly$q$, NULL, $q$["Up to 2,000 emails/month","Unlimited contacts and projects"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$Keila Cloud S$q$, $q$EUR 16/month$q$, $q$Monthly$q$, NULL, $q$["Up to 5,000 emails/month"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$Keila Cloud M$q$, $q$EUR 32/month$q$, $q$Monthly$q$, NULL, $q$["Up to 15,000 emails/month"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$Keila Cloud L$q$, $q$EUR 64/month$q$, $q$Monthly$q$, NULL, $q$["Up to 50,000 emails/month"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$Keila Cloud XL$q$, $q$EUR 128/month$q$, $q$Monthly$q$, NULL, $q$["Up to 100,000 emails/month"]$q$::jsonb, 5);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$Keila Cloud XXL$q$, $q$EUR 256/month$q$, $q$Monthly$q$, NULL, $q$["Up to 250,000 emails/month"]$q$::jsonb, 6);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Keila is an open-source email newsletter platform built in Elixir and Phoenix, developed by pentacent and operated by the Germany-based Pentacent, Philipp Schmieder Medien. It is released under the AGPLv3 license with no proprietary features gated behind the paid version.$q$, $q$It can be run fully self-hosted via Docker at no cost, or used as Keila Cloud, a managed service hosted entirely in Germany and France for strict European privacy standards.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Keila offers a visual block editor plus Markdown and MJML support for composing campaigns, customizable sign-up forms, and contact segmentation through both a visual editor and a query-style segment language.$q$, $q$It includes privacy-respecting analytics that can be disabled with one click, bot protection via hCaptcha or Friendly Captcha, double opt-in, Liquid templating for personalization, and a REST API with a beta Zapier integration.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c94c98e6-ef4f-4e3b-95b2-929dc548f9d9', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Self-hosting Keila via Docker is completely free, with unlimited contacts and projects and no feature restrictions compared to the paid cloud version.$q$, $q$Keila Cloud is priced in six volume-based tiers from EUR 8 per month for 2,000 emails up to EUR 256 per month for 250,000 emails, with unlimited contacts on every tier and no permanent free plan.$q$]::text[], 2);
